// src/pages/admin/MasterAdminDashboard.js
import React, { useState, useEffect, useCallback } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import { useRole } from '../../context/RoleContext';
import { useToast } from '../../context/ToastContext';
import api from '../../services/api';
import './AdminPages.css';

const MasterAdminDashboard = () => {
    const { user } = useAuth();
    const { isRole } = useRole();
    const { showSuccess, showError } = useToast();
    const navigate = useNavigate();
    const [activeTab, setActiveTab] = useState('overview');
    const [stats, setStats] = useState(null);
    const [pendingRequests, setPendingRequests] = useState([]);
    const [users, setUsers] = useState([]);
    const [roles, setRoles] = useState([]);
    const [loading, setLoading] = useState(true);
    
    // Separate modal states
    const [verifyModal, setVerifyModal] = useState({ isOpen: false, user: null, role: '' });
    const [rejectModal, setRejectModal] = useState({ isOpen: false, user: null, reason: '' });
    const [deleteModal, setDeleteModal] = useState({ isOpen: false, user: null });
    const [roleModal, setRoleModal] = useState({ isOpen: false, user: null, role: '' });

    const fetchDashboardData = useCallback(async () => {
        setLoading(true);
        try {
            const [statsRes, requestsRes, usersRes, rolesRes] = await Promise.all([
                api.get('/master-admin/statistics'),
                api.get('/master-admin/role-requests/pending'),
                api.get('/master-admin/users'),
                api.get('/roles')
            ]);
            setStats(statsRes.data);
            setPendingRequests(requestsRes.data);
            setUsers(usersRes.data);
            setRoles(rolesRes.data);
        } catch (error) {
            showError('Failed to load dashboard data');
            console.error('Dashboard fetch error:', error);
        } finally {
            setLoading(false);
        }
    }, [showError]);

    useEffect(() => {
        if (!isRole('master_admin')) {
            navigate('/dashboard');
            return;
        }
        fetchDashboardData();
    }, [isRole, navigate, fetchDashboardData]);

    // Handle Role Request Approval
    const handleApproveRequest = async (requestId) => {
        try {
            await api.post(`/master-admin/role-requests/${requestId}/approve`);
            showSuccess('Role request approved successfully');
            fetchDashboardData();
        } catch (error) {
            showError('Failed to approve request');
            console.error('Approve error:', error);
        }
    };

    // Handle Role Request Rejection
    const handleRejectRequest = async () => {
        if (!rejectModal.reason) {
            showError('Please provide a rejection reason');
            return;
        }
        try {
            await api.post(`/master-admin/role-requests/${rejectModal.user.id}/reject`, { rejectionReason: rejectModal.reason });
            showSuccess('Role request rejected');
            fetchDashboardData();
            setRejectModal({ isOpen: false, user: null, reason: '' });
        } catch (error) {
            showError('Failed to reject request');
            console.error('Reject error:', error);
        }
    };

    // Handle User Verification
    const handleVerifyUser = async () => {
        if (!verifyModal.user || !verifyModal.role) {
            showError('Please select a role for the user');
            return;
        }
        try {
            await api.put(`/master-admin/users/${verifyModal.user.id}/verify`, { role: verifyModal.role });
            showSuccess(`User "${verifyModal.user.username}" verified successfully as ${verifyModal.role.replace('_', ' ').toUpperCase()}`);
            fetchDashboardData();
            setVerifyModal({ isOpen: false, user: null, role: '' });
        } catch (error) {
            showError('Failed to verify user');
            console.error('Verify error:', error);
        }
    };

    // Handle Role Update
    const handleUpdateRole = async () => {
        if (!roleModal.user || !roleModal.role) {
            showError('Please select a role');
            return;
        }
        try {
            await api.put(`/master-admin/users/${roleModal.user.id}/role`, { role: roleModal.role });
            showSuccess(`User "${roleModal.user.username}" role updated to ${roleModal.role.replace('_', ' ').toUpperCase()}`);
            fetchDashboardData();
            setRoleModal({ isOpen: false, user: null, role: '' });
        } catch (error) {
            showError('Failed to update user role');
            console.error('Update role error:', error);
        }
    };

    // Handle User Deletion
    const handleDeleteUser = async () => {
        try {
            await api.delete(`/master-admin/users/${deleteModal.user.id}`);
            showSuccess(`User "${deleteModal.user.username}" deleted successfully`);
            fetchDashboardData();
            setDeleteModal({ isOpen: false, user: null });
        } catch (error) {
            showError('Failed to delete user');
            console.error('Delete error:', error);
        }
    };

    const getRoleDisplayName = (role) => {
        if (!role) return 'N/A';
        const roleMap = {
            'master_admin': 'Master Admin',
            'doctor': 'Doctor',
            'nurse': 'Nurse',
            'patient': 'Patient',
            'diagnostic_staff': 'Diagnostic Staff',
            'lab_technician': 'Lab Technician',
            'radiologist': 'Radiologist',
            'therapeutic_staff': 'Therapeutic Staff',
            'physiotherapist': 'Physiotherapist',
            'nutritionist': 'Nutritionist',
            'pharmacist': 'Pharmacist',
            'receptionist': 'Receptionist',
            'billing_officer': 'Billing Officer',
            'ict_admin': 'ICT Admin',
            'hr_admin': 'HR Admin',
            'department_head': 'Department Head'
        };
        return roleMap[role] || role.replace(/_/g, ' ').toUpperCase();
    };

    const getVerificationBadge = (status) => {
        switch(status) {
            case 'approved':
                return <span className="badge-success">✓ Verified</span>;
            case 'pending':
                return <span className="badge-warning">⏳ Pending</span>;
            case 'rejected':
                return <span className="badge-danger">✗ Rejected</span>;
            default:
                return <span className="badge-secondary">{status}</span>;
        }
    };

    if (loading) return <div className="loading">Loading dashboard...</div>;

    return (
        <div className="master-admin-dashboard">
            <div className="dashboard-header">
                <h1>Master Admin Dashboard</h1>
                <p>Welcome back, {user?.username}</p>
            </div>

            {/* Stats Cards */}
            {stats && (
                <div className="stats-grid">
                    <div className="stat-card">
                        <div className="stat-value">{stats.totalUsers?.count || 0}</div>
                        <div className="stat-label">Total Users</div>
                    </div>
                    <div className="stat-card">
                        <div className="stat-value">{stats.pendingVerification?.count || 0}</div>
                        <div className="stat-label">Pending Verification</div>
                    </div>
                    <div className="stat-card">
                        <div className="stat-value">{stats.pendingRequests?.count || 0}</div>
                        <div className="stat-label">Role Requests</div>
                    </div>
                    <div className="stat-card">
                        <div className="stat-value">{stats.totalRoles?.count || 0}</div>
                        <div className="stat-label">System Roles</div>
                    </div>
                </div>
            )}

            {/* Tabs */}
            <div className="admin-tabs">
                <button 
                    className={`tab ${activeTab === 'overview' ? 'active' : ''}`}
                    onClick={() => setActiveTab('overview')}
                >
                    📊 Overview
                </button>
                <button 
                    className={`tab ${activeTab === 'requests' ? 'active' : ''}`}
                    onClick={() => setActiveTab('requests')}
                >
                    📝 Role Requests ({pendingRequests.length})
                </button>
                <button 
                    className={`tab ${activeTab === 'users' ? 'active' : ''}`}
                    onClick={() => setActiveTab('users')}
                >
                    👥 User Management ({users.length})
                </button>
                <button 
                    className={`tab ${activeTab === 'roles' ? 'active' : ''}`}
                    onClick={() => setActiveTab('roles')}
                >
                    🔧 Role Management
                </button>
            </div>

            {/* Overview Tab */}
            {activeTab === 'overview' && stats && (
                <div className="overview-content">
                    <div className="role-distribution">
                        <h3>Role Distribution</h3>
                        <div className="distribution-list">
                            {stats.roleDistribution?.map(role => (
                                <div key={role.role} className="distribution-item">
                                    <span className="role-name">{getRoleDisplayName(role.role)}</span>
                                    <div className="role-count-bar">
                                        <div className="role-count-number">{role.count}</div>
                                        <div className="role-count-percent">
                                            {((role.count / stats.totalUsers?.count) * 100).toFixed(1)}%
                                        </div>
                                    </div>
                                </div>
                            ))}
                        </div>
                    </div>
                </div>
            )}

            {/* Role Requests Tab */}
            {activeTab === 'requests' && (
                <div className="requests-content">
                    {pendingRequests.length === 0 ? (
                        <div className="empty-state">No pending role requests</div>
                    ) : (
                        <div className="requests-list">
                            {pendingRequests.map(request => (
                                <div key={request.id} className="request-card">
                                    <div className="request-header">
                                        <h3>{request.username}</h3>
                                        <span className="badge-warning">Pending</span>
                                    </div>
                                    <div className="request-details">
                                        <p><strong>Requested Role:</strong> {getRoleDisplayName(request.requested_role)}</p>
                                        <p><strong>Email:</strong> {request.email}</p>
                                        {request.reason && <p><strong>Reason:</strong> {request.reason}</p>}
                                        <p><strong>Submitted:</strong> {new Date(request.created_at).toLocaleString()}</p>
                                    </div>
                                    <div className="request-actions">
                                        <button 
                                            className="btn-success"
                                            onClick={() => handleApproveRequest(request.id)}
                                        >
                                            ✓ Approve
                                        </button>
                                        <button 
                                            className="btn-danger"
                                            onClick={() => setRejectModal({ isOpen: true, user: request, reason: '' })}
                                        >
                                            ✗ Reject
                                        </button>
                                    </div>
                                </div>
                            ))}
                        </div>
                    )}
                </div>
            )}

            {/* User Management Tab - Clean Table Format */}
            {activeTab === 'users' && (
                <div className="users-content">
                    <div className="users-table-container">
                        <table className="users-table">
                            <thead>
                                <tr>
                                    <th>ID</th>
                                    <th>Username</th>
                                    <th>Email</th>
                                    <th>Role</th>
                                    <th>Status</th>
                                    <th>Joined</th>
                                    <th>Actions</th>
                                </tr>
                            </thead>
                            <tbody>
                                {users.map(u => (
                                    <tr key={u.id}>
                                        <td className="user-id">{u.id}</td>
                                        <td className="user-username">
                                            <strong>{u.username}</strong>
                                            {u.verification_status === 'pending' && (
                                                <span className="pending-badge">Pending</span>
                                            )}
                                        </td>
                                        <td className="user-email">{u.email || '-'}</td>
                                        <td className="user-role">
                                            <span className={`role-badge role-${u.role}`}>
                                                {getRoleDisplayName(u.role)}
                                            </span>
                                        </td>
                                        <td className="user-status">
                                            {getVerificationBadge(u.verification_status)}
                                        </td>
                                        <td className="user-joined">
                                            {new Date(u.created_at).toLocaleDateString()}
                                        </td>
                                        <td className="user-actions">
                                            <div className="action-buttons">
                                                {u.verification_status === 'pending' && (
                                                    <button 
                                                        className="btn-icon btn-verify"
                                                        onClick={() => setVerifyModal({ isOpen: true, user: u, role: u.role })}
                                                        title="Verify User"
                                                    >
                                                        ✓ Verify
                                                    </button>
                                                )}
                                                <button 
                                                    className="btn-icon btn-role"
                                                    onClick={() => setRoleModal({ isOpen: true, user: u, role: u.role })}
                                                    title="Change Role"
                                                >
                                                    🔄 Role
                                                </button>
                                                {u.role !== 'master_admin' && (
                                                    <button 
                                                        className="btn-icon btn-delete"
                                                        onClick={() => setDeleteModal({ isOpen: true, user: u })}
                                                        title="Delete User"
                                                    >
                                                        🗑️ Delete
                                                    </button>
                                                )}
                                            </div>
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                </div>
            )}

            {/* Role Management Tab */}
            {activeTab === 'roles' && (
                <div className="roles-content">
                    <div className="roles-header">
                        <button 
                            className="btn-primary"
                            onClick={() => navigate('/admin/roles')}
                        >
                            + Manage Roles
                        </button>
                    </div>
                    <div className="roles-list">
                        {roles.map(role => (
                            <div key={role.id} className="role-item">
                                <div className="role-info">
                                    <h4>{getRoleDisplayName(role.name)}</h4>
                                    <p>{role.description || 'No description'}</p>
                                    <span className="permissions-count">
                                        {role.permissions?.length || 0} permissions
                                    </span>
                                </div>
                            </div>
                        ))}
                    </div>
                </div>
            )}

            {/* Reject Modal */}
            {rejectModal.isOpen && (
                <div className="modal-overlay" onClick={() => setRejectModal({ isOpen: false, user: null, reason: '' })}>
                    <div className="modal-content" onClick={e => e.stopPropagation()}>
                        <h3>Reject Role Request</h3>
                        <p>User: <strong>{rejectModal.user?.username}</strong></p>
                        <p>Requested Role: <strong>{getRoleDisplayName(rejectModal.user?.requested_role)}</strong></p>
                        <div className="form-group">
                            <label>Rejection Reason *</label>
                            <textarea
                                value={rejectModal.reason}
                                onChange={(e) => setRejectModal({ ...rejectModal, reason: e.target.value })}
                                rows="4"
                                placeholder="Please provide a reason for rejection..."
                                autoFocus
                            />
                        </div>
                        <div className="modal-actions">
                            <button 
                                className="btn-danger"
                                onClick={handleRejectRequest}
                            >
                                Confirm Rejection
                            </button>
                            <button 
                                className="btn-secondary"
                                onClick={() => setRejectModal({ isOpen: false, user: null, reason: '' })}
                            >
                                Cancel
                            </button>
                        </div>
                    </div>
                </div>
            )}

            {/* Verify Modal */}
            {verifyModal.isOpen && (
                <div className="modal-overlay" onClick={() => setVerifyModal({ isOpen: false, user: null, role: '' })}>
                    <div className="modal-content" onClick={e => e.stopPropagation()}>
                        <h3>Verify User</h3>
                        <p>User: <strong>{verifyModal.user?.username}</strong></p>
                        <p>Current Role: <strong>{getRoleDisplayName(verifyModal.user?.role)}</strong></p>
                        
                        <div className="form-group">
                            <label>Assign Role *</label>
                            <select 
                                value={verifyModal.role}
                                onChange={(e) => setVerifyModal({ ...verifyModal, role: e.target.value })}
                                className="role-select"
                            >
                                {roles.map(role => (
                                    <option key={role.id} value={role.name}>
                                        {getRoleDisplayName(role.name)}
                                    </option>
                                ))}
                            </select>
                        </div>
                        
                        <div className="modal-actions">
                            <button 
                                className="btn-success"
                                onClick={handleVerifyUser}
                            >
                                Verify User
                            </button>
                            <button 
                                className="btn-secondary"
                                onClick={() => setVerifyModal({ isOpen: false, user: null, role: '' })}
                            >
                                Cancel
                            </button>
                        </div>
                    </div>
                </div>
            )}

            {/* Change Role Modal */}
            {roleModal.isOpen && (
                <div className="modal-overlay" onClick={() => setRoleModal({ isOpen: false, user: null, role: '' })}>
                    <div className="modal-content" onClick={e => e.stopPropagation()}>
                        <h3>Change Role for {roleModal.user?.username}</h3>
                        <div className="form-group">
                            <label>Select New Role *</label>
                            <select 
                                value={roleModal.role}
                                onChange={(e) => setRoleModal({ ...roleModal, role: e.target.value })}
                                className="role-select"
                            >
                                {roles.map(role => (
                                    <option key={role.id} value={role.name}>
                                        {getRoleDisplayName(role.name)}
                                    </option>
                                ))}
                            </select>
                        </div>
                        <div className="modal-actions">
                            <button 
                                className="btn-primary"
                                onClick={handleUpdateRole}
                            >
                                Update Role
                            </button>
                            <button 
                                className="btn-secondary"
                                onClick={() => setRoleModal({ isOpen: false, user: null, role: '' })}
                            >
                                Cancel
                            </button>
                        </div>
                    </div>
                </div>
            )}

            {/* Delete Confirmation Modal */}
            {deleteModal.isOpen && (
                <div className="modal-overlay" onClick={() => setDeleteModal({ isOpen: false, user: null })}>
                    <div className="modal-content" onClick={e => e.stopPropagation()}>
                        <h3>Delete User</h3>
                        <p>Are you sure you want to delete user <strong>{deleteModal.user?.username}</strong>?</p>
                        <p className="warning-text">⚠️ This action cannot be undone. All data associated with this user will be permanently removed.</p>
                        <div className="modal-actions">
                            <button 
                                className="btn-danger"
                                onClick={handleDeleteUser}
                            >
                                Confirm Delete
                            </button>
                            <button 
                                className="btn-secondary"
                                onClick={() => setDeleteModal({ isOpen: false, user: null })}
                            >
                                Cancel
                            </button>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default MasterAdminDashboard;
